#include <stdio.h>
#include <stdlib.h>

static inline long long pos_drop(long long a, long long b) {
    return a > b ? a - b : 0LL;
}

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N, Q; scanf("%d %d", &N, &Q);
        long long *A = (long long*)malloc((N+2)*sizeof(long long));
        for(int i=1;i<=N;i++) scanf("%lld", &A[i]);
        long long ans = 0;
        for(int i=1;i<N;i++) ans += pos_drop(A[i], A[i+1]);
        while(Q--){
            int idx; long long x; scanf("%d %lld", &idx, &x);
            if(idx>1){
                long long old = pos_drop(A[idx-1], A[idx]);
                long long nw = pos_drop(A[idx-1], x);
                ans += nw - old;
            }
            if(idx<N){
                long long old = pos_drop(A[idx], A[idx+1]);
                long long nw = pos_drop(x, A[idx+1]);
                ans += nw - old;
            }
            A[idx] = x;
            printf("%lld\n", ans);
        }
        free(A);
    }
    return 0;
}

