import java.io.*;
import java.util.*;

public class Main {
    private static long posDrop(long a, long b){
        return a > b ? a - b : 0L;
    }
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        int T = fs.nextInt();
        StringBuilder out = new StringBuilder();
        while (T-- > 0) {
            int N = fs.nextInt();
            int Q = fs.nextInt();
            long[] A = new long[N + 2];
            for (int i = 1; i <= N; i++) A[i] = fs.nextLong();
            long ans = 0;
            for (int i = 1; i < N; i++) ans += posDrop(A[i], A[i + 1]);
            for (int q = 0; q < Q; q++) {
                int idx = fs.nextInt();
                long x = fs.nextLong();
                if (idx > 1) {
                    long old = posDrop(A[idx - 1], A[idx]);
                    long nw = posDrop(A[idx - 1], x);
                    ans += nw - old;
                }
                if (idx < N) {
                    long old = posDrop(A[idx], A[idx + 1]);
                    long nw = posDrop(x, A[idx + 1]);
                    ans += nw - old;
                }
                A[idx] = x;
                out.append(ans).append('\n');
            }
        }
        System.out.print(out.toString());
    }

    // Fast scanner for large input
    static class FastScanner {
        private final InputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream in){ this.in = in; }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        long nextLong() throws IOException {
            int c; do { c = readByte(); } while (c <= ' ');
            boolean neg = false;
            if (c == '-') { neg = true; c = readByte(); }
            long val = 0;
            while (c > ' ') {
                val = val * 10 + (c - '0');
                c = readByte();
            }
            return neg ? -val : val;
        }
        int nextInt() throws IOException { return (int) nextLong(); }
    }
}

