  for(let i=1;i<N;i++) ans += posDrop(A[i], A[i+1]);
  for(let q=0;q<Q;q++){
    const idx = Number(next());
    const x = Number(next());
    if(idx>1){
      const old = posDrop(A[idx-1], A[idx]);
      const nw = posDrop(A[idx-1], x);
      ans += nw - old;
